const items = $input.all();

// El dataset de SECOP trae varias filas con el mismo id_del_proceso
// (una por proveedor invitado); un upsert en lote no puede tocar la
// misma fila dos veces, asi que deduplicamos antes de enviar.
const seen = new Map();
for (const item of items) {
  const p = item.json;
  if (!p.id_del_proceso || seen.has(p.id_del_proceso)) continue;
  seen.set(p.id_del_proceso, {
    id_proceso: p.id_del_proceso,
    entidad_compradora: p.entidad || null,
    objeto: p.descripci_n_del_procedimiento || p.nombre_del_procedimiento || null,
    cuantia: p.precio_base ? Number(p.precio_base) : null,
    estado: p.estado_del_procedimiento || null,
    fecha_publicacion: p.fecha_de_publicacion_del || null,
    fecha_cierre: p.fecha_de_recepcion_de || null,
    enlace: (p.urlproceso && p.urlproceso.url) || null
  });
}
const records = Array.from(seen.values());

return [{ json: { records } }];
